INSERT INTO `v1_4661e3fbc3356d506a96250b1da3450849ef062f617ced56af5ef4c84a811565` VALUES ("ねぇねぇ、騎士クン\n手伝ってあげようよ～", 1.4, 2, "お！\nあそこに困ってそうな人発見！", 1, "春咲 ひより", 1, 1001, 0, "ヒヨリでっす♪\n元気いっぱいがんばるよ♪", 0, 0, 1, 0, 0);
INSERT INTO `v1_4661e3fbc3356d506a96250b1da3450849ef062f617ced56af5ef4c84a811565` VALUES ("わ、わたし、\nなに言ってるんだろ\nあはは…", 1.4, 2, "大切な人を\n守れるようになりたい…って", 1, "草野 優衣", 1, 1002, 0, "みんなみたいに\nわたしも強くならなきゃ", 0, 0, 1, 0, 0);
INSERT INTO `v1_4661e3fbc3356d506a96250b1da3450849ef062f617ced56af5ef4c84a811565` VALUES ("少しは磨かれると思いますよ。", 1.4, 2, "キミに必要な集中力と感性が", 1, "士条 怜", 1, 1003, 0, "フェンシングを始めてみては？", 0, 0, 1, 0, 0);
INSERT INTO `v1_4661e3fbc3356d506a96250b1da3450849ef062f617ced56af5ef4c84a811565` VALUES ("みそぎはねぇ、\nかくれんぼやりたい！", 1.5, 2, "今日はなにして遊ぶ？", 1, "穂高 みそぎ", 1, 1004, 0, "ねぇ、にいちゃん！", 0, 0, 1, 0, 0);
INSERT INTO `v1_4661e3fbc3356d506a96250b1da3450849ef062f617ced56af5ef4c84a811565` VALUES ("私といっしょに…\nいかない？", 1.4, 2, "ねぇ…", 1, "風宮 あかり", 1, 1006, 0, "風宮あかりです", 0, 0, 1, 0, 0);
INSERT INTO `v1_4661e3fbc3356d506a96250b1da3450849ef062f617ced56af5ef4c84a811565` VALUES ("食べ物の恨みは怖いのー", 1.5, 2, "プリンたべたいのー", 1, "出雲 宮子", 1, 1007, 0, "出雲宮子なのー", 0, 0, 1, 0, 0);
INSERT INTO `v1_4661e3fbc3356d506a96250b1da3450849ef062f617ced56af5ef4c84a811565` VALUES ("いいよ。\n見られることは運命さ…", 1.4, 2, "キミもボクの美貌に\n吸い寄せられたんだね。", 1, "虹村 雪", 1, 1008, 0, "ボクは虹村雪。", 0, 0, 1, 0, 0);
INSERT INTO `v1_4661e3fbc3356d506a96250b1da3450849ef062f617ced56af5ef4c84a811565` VALUES ("人呼んで「疾風の冥姫」!!", 1.4, 2, "我が真名は\nアンネローゼ・フォン・シュテッヒパルム！", 1, "柊杏奈", 1, 1009, 0, "フッ…聞いて後悔するがいい！", 0, 0, 1, 0, 0);
INSERT INTO `v1_4661e3fbc3356d506a96250b1da3450849ef062f617ced56af5ef4c84a811565` VALUES ("ほんまおおきにやわ～♪", 1.5, 2, "うさぎさん、\n運命の王子はんに巡りあわせてくれて", 1, "姫宮 真歩", 1, 1010, 0, "マホマホ王国のプリンセス、\nまほ姫どす", 0, 0, 1, 0, 0);
INSERT INTO `v1_4661e3fbc3356d506a96250b1da3450849ef062f617ced56af5ef4c84a811565` VALUES ("ここで会ったが\n100年目～！", 1.4, 2, "生き別れたお兄ちゃんを探して\n三千世界！", 1, "衣之咲 璃乃", 1, 1011, 0, "衣之咲璃乃です！", 0, 0, 1, 0, 0);
INSERT INTO `v1_4661e3fbc3356d506a96250b1da3450849ef062f617ced56af5ef4c84a811565` VALUES ("…って、お願い！\n誰にも言わないでおいて～！", 1.4, 2, "ち、超能力って…\n何のことかな～？", 1, "柏崎 初音", 1, 1012, 0, "私はハツネ、\n結構強いんだよ。\nきらーん☆", 0, 0, 1, 0, 0);
INSERT INTO `v1_4661e3fbc3356d506a96250b1da3450849ef062f617ced56af5ef4c84a811565` VALUES ("ヒデサイまぢ\nGF（グッドフィーリング）～♪", 1.4, 2, "一応カリスマ読モJKやってまっす！", 1, "美波 鈴奈", 1, 1016, 0, "ちょす！\n美波鈴奈だよ～♪", 0, 0, 1, 0, 0);
INSERT INTO `v1_4661e3fbc3356d506a96250b1da3450849ef062f617ced56af5ef4c84a811565` VALUES ("でも、沖縄もとってもいいとこさー", 1.4, 2, "東京は遊園地みたいなところさー", 1, "喜屋武 香織", 1, 1017, 0, "はいたーい。\n喜屋武香織さー。", 0, 0, 1, 0, 0);
INSERT INTO `v1_4661e3fbc3356d506a96250b1da3450849ef062f617ced56af5ef4c84a811565` VALUES ("イオちゃんって呼んでね。", 1.4, 2, "先生って呼ばれるのは\nくすぐったいから", 1, "支倉 伊緒", 1, 1018, 0, "支倉伊緒です。", 0, 0, 1, 0, 0);
INSERT INTO `v1_4661e3fbc3356d506a96250b1da3450849ef062f617ced56af5ef4c84a811565` VALUES ("ミミをおいてかないでぇ～", 1.5, 2, "あ！/\お兄ちゃ～ん\nまってよ～", 1, "茜 ミミ", 1, 1020, 0, "ふえ…？\nミミ、むずかしいこと\nよくわかんない…", 0, 0, 1, 0, 0);
INSERT INTO `v1_4661e3fbc3356d506a96250b1da3450849ef062f617ced56af5ef4c84a811565` VALUES ("ふぇぇぇぇぇん……", 1.5, 2, "あの……\nふぇ……", 1, "栗林 くるみ", 1, 1021, 0, "あ…あの…えっと…\n栗…林…くるみ…です……", 0, 0, 1, 0, 0);
INSERT INTO `v1_4661e3fbc3356d506a96250b1da3450849ef062f617ced56af5ef4c84a811565` VALUES ("なんてありがとうございます！", 1.4, 2, "こんな私に貴重な時間を\n割いていただき、", 1, "風宮 より", 1, 1022, 0, "風宮よりです。\nあああああ！", 0, 0, 1, 0, 0);
INSERT INTO `v1_4661e3fbc3356d506a96250b1da3450849ef062f617ced56af5ef4c84a811565` VALUES ("私こっち行きたいー\nね、早く早くー", 1.5, 2, "おにいちゃんどこいくの？\nえ？", 1, "北条 綾音", 1, 1023, 0, "私、アヤネ！\nぷうきちと一緒についてってあげるね！", 0, 0, 1, 0, 0);
INSERT INTO `v1_4661e3fbc3356d506a96250b1da3450849ef062f617ced56af5ef4c84a811565` VALUES ("これて何か違う…\nあああすみません！", 1.4, 2, "ふ、不束者ですが\nどうぞ末永く…って、", 1, "天野 すずめ", 1, 1025, 0, "わっ…わっ…私、\n天野すずめといいます！", 0, 0, 1, 0, 0);
INSERT INTO `v1_4661e3fbc3356d506a96250b1da3450849ef062f617ced56af5ef4c84a811565` VALUES ("離しませんわ………\n絶対に…!!", 1.4, 2, "あなたは…運命の……\n伴侶……", 1, "倉石 恵理子", 1, 1027, 0, "……クスクス…私は\n…倉石恵理子……", 0, 0, 1, 0, 0);
INSERT INTO `v1_4661e3fbc3356d506a96250b1da3450849ef062f617ced56af5ef4c84a811565` VALUES ("…そうでしょ？？", 1.4, 2, "その無駄を省くことができれば、\nもっと余裕のある暮らしができるっ！", 1, "佐々木 咲恋", 1, 1028, 0, "佐々木咲恋よ。\nねえ、世の中に無駄なことが\n多すぎると思わない？", 0, 0, 1, 0, 0);
INSERT INTO `v1_4661e3fbc3356d506a96250b1da3450849ef062f617ced56af5ef4c84a811565` VALUES ("あはは、\n私もまだまだだなぁ～", 1.4, 2, "ぇっと…\nキミ、私のこと知らないの?!", 1, "桜井 望", 1, 1029, 0, "桜井望だよ！\nよろしくねっ", 0, 0, 1, 0, 0);
INSERT INTO `v1_4661e3fbc3356d506a96250b1da3450849ef062f617ced56af5ef4c84a811565` VALUES ("ショーグン、\nワタシと一緒に天下統一デース！", 1.4, 2, "初めまして、\n私はニノン・ジュベール申すデス！", 1, "ニノン・ジュベール", 1, 1030, 0, "デケデケデンっ！", 0, 0, 1, 0, 0);
INSERT INTO `v1_4661e3fbc3356d506a96250b1da3450849ef062f617ced56af5ef4c84a811565` VALUES ("おかしいですね……", 1.4, 2, "でもって私の隣にいるのが……\nえ、見えない？", 1, "上喜 しのぶ", 1, 1031, 0, "上喜しのぶです。\n手元のドクロが父です。", 0, 0, 1, 0, 0);
INSERT INTO `v1_4661e3fbc3356d506a96250b1da3450849ef062f617ced56af5ef4c84a811565` VALUES ("そう、\nオラのボケに突っ込める相方が…！", 1.5, 2, "けんども\nそれには足りないモンが…", 1, "野戸まひる", 1, 1033, 0, "目指すはビッグな\nお笑い芸人だっぺ！", 0, 0, 1, 0, 0);
INSERT INTO `v1_4661e3fbc3356d506a96250b1da3450849ef062f617ced56af5ef4c84a811565` VALUES ("ちょ\nちょっと一杯飲んできます…！", 1.4, 2, "ちょっと緊張しちゃって…", 1, "綾瀬 ゆかり", 1, 1034, 0, "あの…私…綾瀬ゆかりです…\nあの…ごめんなさい！", 0, 0, 1, 0, 0);
INSERT INTO `v1_4661e3fbc3356d506a96250b1da3450849ef062f617ced56af5ef4c84a811565` VALUES ("これ以上お話しすることは…\nないです！", 1.5, 2, "知らない人とは話しちゃいけないので", 1, "氷川 鏡華", 1, 1036, 0, "氷川鏡華…です", 0, 0, 1, 0, 0);
INSERT INTO `v1_4661e3fbc3356d506a96250b1da3450849ef062f617ced56af5ef4c84a811565` VALUES ("私体が弱いから、\n30分に一度休憩しないと\nいけないんです。", 1.4, 2, "……あ、アラーム。", 1, "柏崎 栞", 1, 1038, 0, "柏崎…栞です。", 0, 0, 1, 0, 0);
INSERT INTO `v1_4661e3fbc3356d506a96250b1da3450849ef062f617ced56af5ef4c84a811565` VALUES ("野に咲く花が、\n唯一の話相手です。", 1.4, 2, "私、一人も友達がいなくて……", 1, "双葉 碧", 1, 1040, 0, "ふ、双葉碧です。", 0, 0, 1, 0, 0);
INSERT INTO `v1_4661e3fbc3356d506a96250b1da3450849ef062f617ced56af5ef4c84a811565` VALUES ("そう思っています。", 1.4, 2, "私の歌声で、\n皆さんが幸せになってくれたらいいなって…", 1, "三角 千歌", 1, 1042, 0, "三角千歌です。", 0, 0, 1, 0, 0);
INSERT INTO `v1_4661e3fbc3356d506a96250b1da3450849ef062f617ced56af5ef4c84a811565` VALUES ("う、疑ってすまなかったな…", 1.4, 2, "あぁ？\nお前のそいつの仲間か？", 1, "安芸 真琴", 1, 1043, 0, "安芸真琴だ。", 0, 0, 1, 0, 0);
INSERT INTO `v1_4661e3fbc3356d506a96250b1da3450849ef062f617ced56af5ef4c84a811565` VALUES ("わらわの偉大な力に\nひれ伏すがいい！\nはっはっは！", 1.4, 2, "生けとし生ける全ての者よ！", 1, "イリヤ・オーンスタイン", 1, 1044, 0, "わらわこそは夜を総べる者！", 0, 0, 1, 0, 0);
INSERT INTO `v1_4661e3fbc3356d506a96250b1da3450849ef062f617ced56af5ef4c84a811565` VALUES ("ｌク、クウカに何かご用ですか!?", 1.4, 2, "ぐふふふふ……はっ！", 1, "遠見 空花", 1, 1045, 0, "そこで騎士は妖精を乱暴に……", 0, 0, 1, 0, 0);
INSERT INTO `v1_4661e3fbc3356d506a96250b1da3450849ef062f617ced56af5ef4c84a811565` VALUES ("う～ん…\n猫ってホントに最高にゃ～♪", 1.4, 2, "自由気ままで♪\n寝て遊んで、食べてケンカして…", 1, "宮坂たまき", 1, 1046, 0, "宮坂たまきにゃ♪\n猫はいいにゃよ？", 0, 0, 1, 0, 0);
INSERT INTO `v1_4661e3fbc3356d506a96250b1da3450849ef062f617ced56af5ef4c84a811565` VALUES ("…と思ったら\nバイトの時間だ！\nまたあとでね！", 1.4, 2, "それでは早速クエストに…", 1, "大神 美冬", 1, 1048, 0, "大神美冬よ！", 0, 0, 1, 0, 0);
INSERT INTO `v1_4661e3fbc3356d506a96250b1da3450849ef062f617ced56af5ef4c84a811565` VALUES ("お姉ちゃんがぜ～んぶ\nやってあげるからね！", 1.4, 2, "クエストもバトルも\n掃除も洗濯も", 1, "星野静流", 1, 1049, 0, "星野静流だよ！", 0, 0, 1, 0, 0);
INSERT INTO `v1_4661e3fbc3356d506a96250b1da3450849ef062f617ced56af5ef4c84a811565` VALUES ("学校では誰もが憧れる\nアイドル的な存在ってやつよ♪", 1.5, 2, "見ての通りの\nセクシー美少女で", 1, "玉泉美咲", 1, 1050, 0, "アタシは玉泉美咲。", 0, 0, 1, 0, 0);
INSERT INTO `v1_4661e3fbc3356d506a96250b1da3450849ef062f617ced56af5ef4c84a811565` VALUES ("？？？？", 1.4, 2, "？？？？", 1, "リマ", 1, 1052, 0, "？？？", 0, 0, 1, 0, 0);
INSERT INTO `v1_4661e3fbc3356d506a96250b1da3450849ef062f617ced56af5ef4c84a811565` VALUES ("そ、そこまでいうなら\nもらってやる", 1.5, 2, "菓子でつろうなどと\n稚拙な策を……", 1, "モニカ・ヴァイスヴィント", 1, 1053, 0, "モニカ・ヴァイスヴィントだ。", 0, 0, 1, 0, 0);
INSERT INTO `v1_4661e3fbc3356d506a96250b1da3450849ef062f617ced56af5ef4c84a811565` VALUES ("そ、そこまでいうなら\nもらってやる", 1.5, 2, "菓子でつろうなどと\n稚拙な策を……", 1, "ペコリーヌ", 1, 1058, 0, "モニカ・ヴァイスヴィントだ。", 0, 0, 1, 0, 0);
INSERT INTO `v1_4661e3fbc3356d506a96250b1da3450849ef062f617ced56af5ef4c84a811565` VALUES ("そ、そこまでいうなら\nもらってやる", 1.5, 2, "菓子でつろうなどと\n稚拙な策を……", 1, "コッコロ", 1, 1059, 0, "モニカ・ヴァイスヴィントだ。", 0, 0, 1, 0, 0);
INSERT INTO `v1_4661e3fbc3356d506a96250b1da3450849ef062f617ced56af5ef4c84a811565` VALUES ("そ、そこまでいうなら\nもらってやる", 1.5, 2, "菓子でつろうなどと\n稚拙な策を……", 1, "キャル", 1, 1060, 0, "モニカ・ヴァイスヴィントだ。", 0, 0, 1, 0, 0);
